var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"헉… 허억… 흐억…….","JPN":"はあ……はあっ……ぐはあっ……","ENG":"*Huff* *Huff*","TWN":"咳……咳咳……咳……"},"stage":{"bg":"VILLAGE1","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"괜찮으신가요?","JPN":"大丈夫ですか？","ENG":"Are you all right?","TWN":"你沒事吧？"},"stage":{"bg":"VILLAGE1","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"감사합니다. 간만의 친절이라 눈물이 앞을 가리네요.","JPN":"ありがとうございます。久々の親切に涙が止まりませんね。","ENG":"Thank you. It's been a while since someone has been kind to me. I might just cry.","TWN":"謝謝你…好久沒遇到這麼親切的人，我都快哭了…"},"stage":{"bg":"VILLAGE1","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"크레데레의 토템으로서의 성능은 어떠셨는지.","JPN":"トーテムとしてのクレデレの性能はいかがでしたか？","ENG":"What did you think of Credere's abilities as a totem?","TWN":"克蕾妲莉的表現很棒吧？"},"stage":{"bg":"VILLAGE1","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"그쪽도 고오맙네요. 마찬가지로 눈물이 앞을 가립니다.","JPN":"そっちもまあ、どーも。同じく涙が止まりません。","ENG":"Thank you sooo much. I'm so touched.","TWN":"我也謝謝你，一樣快哭了。"},"stage":{"bg":"VILLAGE1","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"아싸.","JPN":"やった。","ENG":"Nice.","TWN":"耶嘿。"},"stage":{"bg":"VILLAGE1","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L11_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"끄으으윽…!","JPN":"くうううっ……！","ENG":"Kgh...!","TWN":"咳呃呃呃……！"},"stage":{"bg":"VILLAGE1","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"어쨌든 감사합니다.","JPN":"とにかく、ありがとうございます。","ENG":"Thank you.","TWN":"總之，很謝謝你。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"최근 개업한 음식점이라 그런지 배부르다 해도 서비스를 주셔서 난감한 차였거든요.","JPN":"最近オープンした食堂だからか、ずっとサービスが出てきて、お腹いっぱいなのに困ってるところでした。","ENG":"The restaurant opened recently, and they kept giving me more free food, even though I said I was full.","TWN":"可能是因為最近剛開業的餐廳，即使已經吃飽了，他們還是會拉我去吃，讓我有點為難。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"일주일 만에 2kg 쪘는데, 여기서 더 찌면 진짜 곤란해서…….","JPN":"一週間で2キロ太ってしまって、さらに太るのは本当に困るんで……","ENG":"I gained 2 kg in a week, and I really don't want to gain more weight...","TWN":"一周內長胖2公斤，如果再胖下去真的會很麻煩……"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"…예? 음식점이요?","JPN":"……え？　食堂？","ENG":"...Huh? Restaurant?","TWN":"……蛤？餐廳？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"그나저나 시그마 따님이 여긴 어쩐 일로?","JPN":"それより、シグマお嬢様はどうしてここに？","ENG":"Anyway, what are you doing here, Sigma Lady?","TWN":"不過，西格瑪千金怎麼會在這裡？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"음, 시그마 선장님은 모네 선원을 찾으러 왔어.","JPN":"うん、シグマ船長はモネ船員を探しに来た。","ENG":"Mm. Captain Sigma is here to find Mone.","TWN":"嗯，西格瑪船長是來找莫妮船員的。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"아, 모네라면 분명……","JPN":"あ、モネなら確か……","ENG":"Ah, Mone is–","TWN":"啊，如果是莫妮的話，她在……"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"엄니이이이-!","JPN":"母ちゃーん！","ENG":"Mamaaaaa!","TWN":"媽——媽——！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"못된 아저씨들! 당장 엄니에게서 떨어지는 검다!","JPN":"この悪いおじさんたち！　今すぐ母ちゃんから離れろっす！","ENG":"Mean ruffians! Get away from my mama!","TWN":"壞叔叔們！立刻從我媽媽身邊離開唄！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"안 그러면 모네의 아네모네 펀─치를…","JPN":"じゃないと、モネのアネモネパ～ンチを……","ENG":"Or else, you'll be facing the full wrath of Mone's Anemone Punch–","TWN":"不然就讓你嚐嚐莫妮的必殺銀蓮花─拳！……"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":" 어라.","JPN":" あれ。","ENG":" Huh?","TWN":"……咦？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"시그마 따님? 이게 어떻게 된 검까?","JPN":"シグマお嬢様？　どういうことっすか？","ENG":"Sigma Lady? What's going on?","TWN":"西格瑪千金？這到底是怎麼回事咧？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"후훗. 이분들께서 엄마를 도와주셨단다.","JPN":"ふふっ。この方たちがお母さんを助けてくださったのよ。","ENG":"Ha ha. These people just helped me out.","TWN":"呵呵。剛才是她們幫媽媽忙的喔。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"사장님들이 집요하셨는데 정말 다행이지 뭐야.","JPN":"お店の人がしつこかったんだけど、本当に助かったの。","ENG":"The owners were persistent, so it was a relief to get their help.","TWN":"那幾個餐廳老闆很執著，不過真是慶幸。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"역시 시그마 따님-! 대단함다!","JPN":"さすがシグマお嬢様ー！　すごいっす！","ENG":"Wow, Sigma Lady! That's amazing, ma'am!","TWN":"不愧是西格瑪千金～！好厲害！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"요호호! 선장님에게 이정도는 기본이다, 얼!","JPN":"ヨホホ！　船長としてこのくらいは基本だよ、ARRR！","ENG":"Yo ho ho! I'm the captain! This is nothing! Yarr!","TWN":"喔呵呵！這對船長來說是小事啦！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"요호호! 그런데 옆에 계신 분들은 누구임까, 얼?","JPN":"ヨホホ！　ところで、そばにいる人たちは誰っすか？　ARRR。","ENG":"Yo ho ho! But who are those next to you? Yarr!","TWN":"喔呵呵！不過旁邊這幾位是誰呀！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L38_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"소개하지! 이쪽은 해적단에 새롭게 합류한 유피와 크레데레 선원이다!","JPN":"紹介しよう！　こっちは新しく海賊団に合流したユピとクレデレ船員だ！","ENG":"Let me introduce them! This is Yuppie and Credere, the newest members of the crew!","TWN":"我來給你介紹一下！這邊是新加入海盜團的悠菲和克蕾妲莉船員！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L41_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"예이-. 유피입니다.","JPN":"イェーイ。ユピでーす。","ENG":"Yeah. Yuppie.","TWN":"耶咿——，我是悠菲。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"제가 유피니까 이 사람 말은 걸러 들으세요.","JPN":"私がユピですから、この人の言葉は信じないようにしてくださいね。","ENG":"No, I'm Yuppie, so don't listen to her.","TWN":"不要聽她瞎說，我才是悠菲。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L44_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"오오. 두 분 모두 먼 길 오시느라 고생 많으셨슴다.","JPN":"おお。お二人とも、遠路遥々ご苦労様っす。","ENG":"Ohh. You all traveled a long way to get here, I imagine.","TWN":"喔喔！兩位遠道而來辛苦哩。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"정말로요. 오자마자 펭귄 소동에 휘말려서 얼마나 골치 아팠는데요.","JPN":"本当ですよ。到着してすぐペンギン騒動に巻き込まれて大変だったんです。","ENG":"It was definitely long. And we got caught up in a penguin incident as soon as we got here.","TWN":"確實。剛來就捲入企鵝騷動，真是頭疼……"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"펭귄이라면… 모네 동생들을 말씀하시는 건가요?","JPN":"ペンギンなら……モネのきょうだいのことですか？","ENG":"Penguins... Do you mean Mone's sisters?","TWN":"企鵝……？是莫妮的妹妹們嗎？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"모네 동생? 아까 그 펭귄들이 전부 모네 양의 동생이라고요?","JPN":"モネのきょうだい？　さっきのあのペンギンって、全部モネさんのきょうだいなんですか？","ENG":"Mone's sisters? Are all those penguins your sisters?","TWN":"莫妮的妹妹？剛才那些企鵝全都是莫妮的妹妹嗎！？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"후후. 그게 아니라, 여러분이 보신 펭귄 비슷한 아이들을 마을에서는 모네 동생들이라고 부르고 있어요.","JPN":"ふふ。そうじゃなくて、みなさんが見たペンギンに似た子どもを村ではモネのきょうだいって呼んでます。","ENG":"Ha ha. We call those penguin-like kids Mone's sisters in the town.","TWN":"呵呵。不是的，那些在村子裡看到的企鵝，大家都喜歡叫牠們莫妮的妹妹。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"우리 마을의 명물임다. 인형 옷 안에 먹을 걸 넣으면 펑! 하고 튀어나오지 말임다.","JPN":"この村の名物っす。着ぐるみの中に食べ物を入れると、ボーン！　って出てくるっす。","ENG":"They're what our town is famous for. You put food in the costume, and they come out, like poof!","TWN":"這是我們村的特色。如果在玩偶裝裡放吃的東西，牠就會“砰！——”地一聲彈出來喔。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"넷튜브에서 엄청 유행했는데 모르셨슴까?","JPN":"ネットチューブで結構流行ったんすけど、知らなかったっすか？","ENG":"It was trending on NetTube, you didn't know?","TWN":"這個在網路上非常流行，你們不知道嗎？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L6_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"네… 뭐, 한동안 먹고 사느라 바빴거든요.","JPN":"はい……まあ、しばらく忙しかったんで。","ENG":"Yeah... Well, I was busy making a living.","TWN":"啊……因為最近一直忙著打工賺錢。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"헉. 그런 안타까운 사연이.","JPN":"はっ。そんな悲しい事情が。","ENG":"Oh. Such a tragic story.","TWN":"嚇，真是個令人心酸的理由。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"고생한 유피에게 칭찬도장 하나를 드리겠습니다.","JPN":"苦労したユピに、よくできましたステッカーを一つ差し上げましょう。","ENG":"Here is another stamp for Yuppie, who went through so much.","TWN":"再給辛苦的悠菲一個好寶寶印章。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"필요 없어.","JPN":"いらない。","ENG":"I don't need it.","TWN":"沒那個必要。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"그래도 죄송함다. 모처럼 와주셨는데 일이 바빠서 대접해드리기는 힘들 것 같슴다.","JPN":"でも、すみません。せっかく来てくれたのに、仕事が忙しくておもてなしはできなさそうっす。","ENG":"I'm sorry. You made it all the way out here, but I'm swamped and I'm afraid I can't keep you company for long.","TWN":"但是對不起撒。難得來一趟，因為工作太忙，沒辦法好好招待西格瑪千金。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"선장님이 새 동료분들을 소개하러 와주셨는데, 정말이지 면목없슴다.","JPN":"船長が新しい仲間を紹介しに来てくれたのに、本当に面目ないっす。","ENG":"It really is a shame, considering you came here to introduce your new members, ma'am.","TWN":"船長還特地給莫妮介紹新同伴，真是慚愧呢。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"아, 그건…….","JPN":"あ、それは……","ENG":"Ah, that's...","TWN":"喔，那個……"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"어라, 그러려고 오신 게 아닌검까?","JPN":"あれ、そのために来たわけじゃないっすか？","ENG":"Oh, was that not the purpose of your visit?","TWN":"嗯？不是為了這個來的嗎？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"설마요. 소개도 끝났으니 슬슬 본론으로 돌아가죠.","JPN":"まさか。紹介も終わったことだし、そろそろ本題に入りましょう。","ENG":"Of course not. Let's get to the point.","TWN":"當然不是。介紹時間結束，該回到正題了。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"모네 양. 혹시 최근 화제인 보물에 대해 알고 계시나요?","JPN":"モネさん。最近話題になってるお宝のことを知ってますか？","ENG":"Mone. Have you heard of this treasure that's been the talk of the town?","TWN":"莫妮，你知道最近很紅的那個寶箱嗎？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"}]`);export{e as default};